import { PUBLIC_GA_MEASUREMENT_ID } from '$env/static/public';

declare global {
  interface Window {
    dataLayer: any[];
    gtag: (...args: any[]) => void;
  }
}

export const initAnalytics = () => {
  if (typeof window === 'undefined') return;

  const script = document.createElement('script');
  script.async = true;
  script.src = `https://www.googletagmanager.com/gtag/js?id=${PUBLIC_GA_MEASUREMENT_ID}`;
  document.head.appendChild(script);

  window.dataLayer = window.dataLayer || [];
  window.gtag = function () {
    window.dataLayer.push(arguments);
  };
  window.gtag('js', new Date());

  // Disable automatic pageview to handle it manually for SPA routing
  window.gtag('config', PUBLIC_GA_MEASUREMENT_ID, {
    send_page_view: false,
  });
};

export const capturePageView = (url: string) => {
  if (typeof window !== 'undefined' && typeof window.gtag === 'function') {
    window.gtag('config', PUBLIC_GA_MEASUREMENT_ID, {
      page_path: url,
    });
  }
};
