<script lang="ts">
  import '../app.css';

  import { onMount } from 'svelte';
  import { env } from '$env/dynamic/public';
  import { browser, dev } from '$app/environment';
  import { afterNavigate } from '$app/navigation';
  import { page } from '$app/stores';

  import { i18n } from '$lib/i18n';
  import { Header, Footer, Sidebar } from '$lib/components/layout';
  import { ToastContainer, CommandPalette, Seo } from '$lib/components/ui';
  import { getPageBySlug, getToolBySlug } from '$lib/registry';
  import { initAnalytics, capturePageView } from '$lib/services/ga4';

  let { children } = $props();

  let isSidebarOpen = $state(false);

  let currentTool = $derived(getToolBySlug($page.url.pathname.split('/')[1]));
  let currentPageData = $derived(getPageBySlug($page.url.pathname.split('/')[1]));

  let pageTitle = $derived.by(() => {
    if ($page.url.pathname === '/') return `${i18n.t('app.title')} | ${i18n.t('app.tagline')}`;
    if (currentTool) return i18n.t(currentTool.name);
    if (currentPageData) return i18n.t(currentPageData.name);
    return i18n.t('page.home');
  });

  let pageDescription = $derived.by(() => {
    if ($page.url.pathname === '/') return i18n.t('app.description.home');
    if (currentTool && currentTool.description) return i18n.t(currentTool.description as string);
    if (currentPageData && currentPageData.description) return i18n.t(currentPageData.description as string);
    return i18n.t('app.description.home');
  });

  let pageKeywords = $derived.by(() => {
    if (currentTool && currentTool.keywords) {
      return currentTool.keywords.join(', ');
    }
    return undefined;
  });

  onMount(() => {
    if (browser && !dev) {
      initAnalytics();
    }
  });

  afterNavigate(() => {
    if (browser && !dev) {
      capturePageView($page.url.pathname);
    }
  });
</script>

<Seo 
  title={pageTitle} 
  description={pageDescription} 
  keywords={pageKeywords}
  isTool={!!currentTool} 
  type={currentTool ? "WebApplication" : "website"}
/>

<svelte:head>
  {#if import.meta.env.VITE_PUBLIC_BUILD !== 'true' && env.PUBLIC_GTM_ID}
    <!-- Google Tag Manager -->
    {@html `<script>(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({'gtm.start':
    new Date().getTime(),event:'gtm.js'});var f=d.getElementsByTagName(s)[0],
    j=d.createElement(s),dl=l!='dataLayer'?'&l='+l:'';j.async=true;j.src=
    'https://www.googletagmanager.com/gtm.js?id='+i+dl;f.parentNode.insertBefore(j,f);
    })(window,document,'script','dataLayer','${env.PUBLIC_GTM_ID}');</script>`}
    <!-- End Google Tag Manager -->
  {/if}
</svelte:head>

{#if import.meta.env.VITE_PUBLIC_BUILD !== 'true' && env.PUBLIC_GTM_ID}
  <!-- Google Tag Manager (noscript) -->
  <noscript><iframe src="https://www.googletagmanager.com/ns.html?id={env.PUBLIC_GTM_ID}"
  height="0" width="0" style="display:none;visibility:hidden" title="GTM"></iframe></noscript>
  <!-- End Google Tag Manager (noscript) -->
{/if}

<div class="flex flex-col h-screen bg-gray-50 dark:bg-gray-950 font-sans text-gray-900 dark:text-gray-100 transition-colors duration-200">
  <ToastContainer />

  <Header bind:isSidebarOpen={isSidebarOpen} {pageTitle} />

  <div class="flex flex-1 overflow-hidden relative">

    {#if isSidebarOpen}
      <button 
        class="absolute inset-0 z-20 w-full border-none p-0 cursor-default bg-gray-900/50 backdrop-blur-sm lg:hidden"
        aria-label="Close sidebar"
        onclick={() => isSidebarOpen = false}
      ></button>
    {/if}

    <Sidebar bind:isOpen={isSidebarOpen} />

    <main class="flex-1 flex flex-col min-w-0 overflow-hidden">

      <div class="flex-1 overflow-y-auto debox-scrollbar">
        <div class="w-full max-w-8xl mx-auto p-4 sm:p-6">
          {@render children()}
        </div>
      </div>

      <div class="shrink-0 border-t border-gray-200 dark:border-gray-800 bg-white/30 dark:bg-gray-900/30">
        <div class="max-w-8xl mx-auto px-4 sm:px-8">
          <Footer />
        </div>
      </div>

    </main>
  </div>

  <CommandPalette />
</div>